        "blokowanie terminów w grafiku",
        "przeglądanie danych pacjentów przypisanych do wizyt",
        "zarządzanie własnym profilem"
      ]
    },
    {
      "name": "Administrator",
      "permissions": [
        "zarządzanie kontami użytkowników",
        "zarządzanie kontami specjalistów",
        "przeglądanie wszystkich rezerwacji",
        "anulowanie dowolnej rezerwacji",
        "generowanie raportów systemowych",
        "konfiguracja systemu",
        "zarządzanie kategoriami specjalistów"
      ]
    },
    {
      "name": "Recepcjonista",
      "permissions": [
        "przeglądanie dostępnych terminów wszystkich specjalistów",
        "dokonywanie rezerwacji w imieniu pacjenta",
        "anulowanie rezerwacji pacjenta",
        "przeglądanie listy rezerwacji",
        "rejestrowanie nowych pacjentów"
      ]
    }
  ],
  "functional_requirements": [
    {
      "id": "FR1",
      "description": "System umożliwia rejestrację nowych użytkowników z przypisaniem odpowiedniej roli (Pacjent, Specjalista, Recepcjonista, Administrator)."
    },
    {
      "id": "FR2",
      "description": "System umożliwia logowanie użytkowników za pomocą adresu e-mail i hasła oraz weryfikuje ich tożsamość przed przyznaniem dostępu."
    },
    {
      "id": "FR3",
      "description": "System wyświetla listę dostępnych terminów wizyt z możliwością filtrowania według specjalisty, daty, godziny oraz specjalizacji."
    },
    {
      "id": "FR4",
      "description": "System umożliwia pacjentowi dokonanie rezerwacji wybranego terminu u wybranego specjalisty."
    },
    {
      "id": "FR5",
      "description": "System zapobiega konfliktom rezerwacji poprzez blokowanie terminu natychmiast po jego zarezerwowaniu, uniemożliwiając równoczesną rezerwację tego samego terminu przez dwóch użytkowników."
    },
    {
      "id": "FR6",
      "description": "System umożliwia pacjentowi anulowanie własnej rezerwacji z zachowaniem określonego limitu czasowego przed planowaną wizytą."
    },
    {
      "id": "FR7",
      "description": "System wysyła powiadomienia e-mail do pacjenta i specjalisty po dokonaniu, potwierdzeniu lub anulowaniu rezerwacji."
    },
    {
      "id": "FR8",
      "description": "System wysyła automatyczne przypomnienia o zbliżającej się wizycie do pacjenta i specjalisty w określonym czasie przed wizytą."
    },
    {
      "id": "FR9",
      "description": "Specjalista może definiować swój grafik dostępności, określając dostępne dni i godziny przyjęć."
    },
    {
      "id": "FR10",
      "description": "Specjalista może blokować wybrane terminy w swoim grafiku, czyniąc je niedostępnymi dla rezerwacji."
    },
    {
      "id": "FR11",
      "description": "Specjalista może przeglądać listę wszystkich zarezerwowanych wizyt w swoim grafiku wraz z danymi pacjentów."
    },
    {
      "id": "FR12",
      "description": "Specjalista może potwierdzić lub odwołać rezerwację dokonaną przez pacjenta, a system powiadamia pacjenta o zmianie statusu."
    },
    {
      "id": "FR13",
      "description": "Pacjent może przeglądać historię swoich poprzednich i nadchodzących wizyt wraz z ich statusami."
    },
    {
      "id": "FR14",
      "description": "Recepcjonista może dokonywać rezerwacji wizyt w imieniu pacjenta oraz anulować istniejące rezerwacje."
    },
    {
      "id": "FR15",
      "description": "Administrator może zarządzać kontami wszystkich użytkowników, w tym tworzyć, edytować, dezaktywować i usuwać konta."
    },
    {
      "id": "FR16",
      "description": "Administrator może przeglądać wszystkie rezerwacje w systemie oraz generować raporty dotyczące obłożenia grafików i aktywności użytkowników."
    },
    {
      "id": "FR17",
      "description": "System umożliwia zarządzanie kategoriami i specjalizacjami specjalistów, pozwalając na przypisanie specjalisty do jednej lub wielu specjalizacji."
    },
    {
      "id": "FR18",
      "description": "System rejestruje historię zmian statusów rezerwacji wraz z informacją o użytkowniku dokonującym zmiany i znacznikiem czasowym."
    },
    {
      "id": "FR19",
      "description": "System umożliwia użytkownikowi edycję danych własnego profilu, takich jak dane kontaktowe i hasło."
    },
    {
      "id": "FR20",
      "description": "System obsługuje wyszukiwanie specjalistów według imienia, nazwiska lub specjalizacji i wyświetla ich profile z dostępnymi terminami."
    }
  ]
}

