{
  "acceptance_criteria": [
    {
      "id": "AC1",
      "given": "Użytkownik nie posiada konta w systemie i znajduje się na stronie rejestracji",
      "when": "Użytkownik wypełnia formularz rejestracji podając unikalny adres e-mail, hasło spełniające wymagania bezpieczeństwa oraz dane osobowe (imię, nazwisko) i zatwierdza formularz",
      "then": "System tworzy nowe konto użytkownika, wysyła e-mail weryfikacyjny na podany adres i wyświetla komunikat o pomyślnej rejestracji"
    },
    {
      "id": "AC2",
      "given": "Użytkownik posiada aktywne konto w systemie i znajduje się na stronie logowania",
      "when": "Użytkownik wprowadza poprawny adres e-mail i hasło oraz zatwierdza formularz logowania",
      "then": "System uwierzytelnia użytkownika, tworzy sesję i przekierowuje go do panelu odpowiedniego dla jego roli"
    },
    {
      "id": "AC3",
      "given": "Zalogowany pacjent znajduje się na stronie przeglądania terminów wizyt",
      "when": "Pacjent stosuje filtry według specjalizacji, specjalisty, daty lub godziny",
      "then": "System wyświetla listę dostępnych terminów spełniających wybrane kryteria filtrowania, posortowanych chronologicznie"
    },
    {
      "id": "AC4",
      "given": "Zalogowany pacjent znajduje się na stronie wyszukiwania specjalistów",
      "when": "Pacjent wprowadza imię, nazwisko lub specjalizację specjalisty w pole wyszukiwania i zatwierdza zapytanie",
      "then": "System wyświetla listę pasujących specjalistów wraz z możliwością przejścia do profilu każdego z nich i podglądu dostępnych terminów"
    },
    {
      "id": "AC5",
      "given": "Zalogowany pacjent przegląda dostępne terminy i wybrał konkretny termin u wybranego specjalisty",
      "when": "Pacjent klika przycisk rezerwacji wybranego terminu i potwierdza chęć rezerwacji",
      "then": "System blokuje wybrany termin, tworzy rezerwację ze statusem oczekującym na potwierdzenie i wyświetla pacjentowi potwierdzenie dokonania rezerwacji"
    },
    {
      "id": "AC6",
      "given": "Zalogowany pacjent posiada aktywną rezerwację wizyty i czas do wizyty przekracza wymagane minimum wyprzedzenia",
      "when": "Pacjent wybiera opcję anulowania rezerwacji i potwierdza decyzję",
      "then": "System zmienia status rezerwacji na anulowaną, zwalnia termin w grafiku specjalisty i wysyła powiadomienia e-mail do pacjenta i specjalisty"
    },
    {
      "id": "AC7",
      "given": "Zalogowany pacjent znajduje się w swoim panelu użytkownika",
      "when": "Pacjent przechodzi do sekcji historii wizyt",
      "then": "System wyświetla listę wszystkich poprzednich i nadchodzących wizyt pacjenta wraz z datą, godziną, nazwiskiem specjalisty i aktualnym statusem każdej wizyty"
    },
    {
      "id": "AC8",
      "given": "Pacjent dokonał, potwierdził lub anulował rezerwację wizyty",
      "when": "System przetwarza zmianę statusu rezerwacji",
      "then": "System automatycznie wysyła e-mail na adres pacjenta zawierający informację o rodzaju zmiany, szczegółach wizyty (data, godzina, specjalista) i aktualnym statusie rezerwacji"
    },
    {
      "id": "AC9",
      "given": "Pacjent posiada potwierdzoną rezerwację wizyty, a do wizyty pozostał określony czas (np. 24 godziny)",
      "when": "System wykrywa zbliżający się termin wizyty zgodnie z harmonogramem przypomnień",
      "then": "System automatycznie wysyła e-mail przypominający pacjentowi o wizycie zawierający datę, godzinę, imię i nazwisko specjalisty oraz lokalizację"
    },
    {
      "id": "AC10",
      "given": "Zalogowany pacjent znajduje się w sekcji edycji profilu",
      "when": "Pacjent zmienia numer telefonu, adres e-mail lub hasło i zapisuje zmiany",
      "then": "System aktualizuje dane profilu pacjenta, w przypadku zmiany e-mail wysyła weryfikację na nowy adres, a w przypadku zmiany hasła wymaga podania aktualnego hasła"
    },
    {
      "id": "AC11",
